// Monthly budget spend limit alert.
// Sums all cost over the rolling 30-day window.
// Amount is in cents — 100000 = $1,000.00.
// Adjust the budget threshold in the final WHERE clause.
FROM metrics-anthropic_metrics.cost-*
| WHERE anthropic.cost.amount IS NOT NULL
| STATS monthly_cost_cents = SUM(anthropic.cost.amount)
| EVAL monthly_cost_usd = ROUND(monthly_cost_cents / 100.0, 2)
| WHERE monthly_cost_cents > 100000
